@import "tailwindcss";

:root {
  --bg:           #E8DCC4;
  --bg-card:      #F4ECD8;
  --bg-card-hi:   #FAF3E0;
  --sage:         #8FA876;
  --sage-deep:    #6E8A57;
  --terracotta:   #C97B5C;
  --terracotta-d: #A55E42;
  --dusk:         #4F6D7A;
  --gold:         #D4A85A;
  --walnut:       #3E2C20;
  --walnut-soft:  #5C4536;
  --line:         #B8A584;

  --font-display: var(--font-fraunces), Georgia, serif;
  --font-body:    var(--font-nunito), system-ui, sans-serif;
  --font-serif:   var(--font-aleo), Georgia, serif;

  --radius:       14px;
  --shadow:       0 2px 0 rgba(62,44,32,.08), 0 8px 24px rgba(62,44,32,.10);
  --shadow-hover: 0 2px 0 rgba(62,44,32,.08), 0 14px 30px rgba(62,44,32,.14);
}

* { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }

body {
  font-family: var(--font-body);
  color: var(--walnut);
  background: var(--bg);
  background-image:
    url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='240' height='240'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='2' stitchTiles='stitch'/><feColorMatrix values='0 0 0 0 0.31  0 0 0 0 0.22  0 0 0 0 0.13  0 0 0 0.05 0'/></filter><rect width='100%' height='100%' filter='url(%23n)'/></svg>");
  background-size: 240px 240px;
  line-height: 1.55;
  -webkit-font-smoothing: antialiased;
}

a { color: var(--terracotta-d); text-decoration: none; border-bottom: 1px dotted var(--terracotta); }
a:hover { color: var(--terracotta); border-bottom-color: var(--terracotta); }

.wrap { max-width: 1040px; margin: 0 auto; padding: 0 28px; }

.top {
  padding: 22px 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-weight: 600;
}
.brand {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 22px;
  color: var(--walnut);
  letter-spacing: -0.01em;
  border: none;
}
.brand .dot { color: var(--terracotta); }
.top nav a {
  margin-left: 22px;
  color: var(--walnut-soft);
  border: none;
  font-size: 15px;
}
.top nav a:hover { color: var(--terracotta); }
.top nav .pill {
  margin-left: 18px;
  padding: 5px 12px;
  font-size: 11px;
}
.top nav .pill:hover { color: var(--walnut-soft); border-color: var(--terracotta); }

.hero {
  padding: 18px 0 8px;
  text-align: center;
  position: relative;
}
.eyebrow {
  font-size: 12px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--dusk);
  font-weight: 800;
  margin-bottom: 14px;
}
.hero h1 {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: clamp(34px, 5.4vw, 52px);
  line-height: 1.05;
  letter-spacing: -0.02em;
  margin: 0 0 10px;
  color: var(--walnut);
}
.hero h1 em {
  font-style: italic;
  color: var(--terracotta);
  font-weight: 600;
}
.hero .lede {
  font-size: clamp(15px, 1.6vw, 17px);
  max-width: 520px;
  margin: 0 auto 22px;
  color: var(--walnut-soft);
}

.wheel-wrap {
  position: relative;
  width: min(560px, 92vw);
  aspect-ratio: 1 / 1;
  margin: 6px auto 18px;
  filter: drop-shadow(0 1px 0 rgba(62,44,32,.05)) drop-shadow(0 12px 24px rgba(62,44,32,.10));
}
.wheel-svg { position: absolute; inset: 0; width: 100%; height: 100%; overflow: visible; }

.point {
  cursor: pointer;
  transition: transform .18s ease;
  transform-box: fill-box;
  transform-origin: center;
}
.point:hover, .point:focus-visible { transform: scale(1.10); outline: none; }
.point.locked { transform: scale(1.10); }
.point .point-tile {
  fill: #FBF4DF;
  stroke: #8B6F47;
  stroke-width: 1.6;
  transition: fill .18s ease, stroke .18s ease;
}
.point:hover .point-tile, .point:focus-visible .point-tile, .point.locked .point-tile {
  fill: #FAF3E0;
  stroke: #C97B5C;
}
.point .point-icon { color: var(--terracotta); }
.point .point-label {
  font-family: var(--font-display);
  font-style: italic;
  font-size: 12px;
  font-weight: 600;
  fill: var(--walnut);
  text-anchor: middle;
  pointer-events: none;
}
.point .point-status {
  font-size: 6px;
  font-weight: 800;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  text-anchor: middle;
  pointer-events: none;
}
.point .point-status.live { fill: var(--sage-deep); }
.point .point-status.wip  { fill: var(--terracotta-d); }
.point .point-status.local { fill: var(--dusk); }

.motif {
  stroke: #8B6F47;
  stroke-width: 1.1;
  stroke-linecap: round;
  stroke-linejoin: round;
  fill: none;
}
.motif-fill { fill: #8FA876; stroke: #6E8A57; stroke-width: 1; }

.vine {
  stroke: #8B6F47;
  stroke-width: 1.2;
  stroke-linecap: round;
  fill: none;
}
.vine-leaf {
  fill: #8FA876;
  stroke: #6E8A57;
  stroke-width: 0.8;
}

.wheel-title {
  font-family: var(--font-display);
  font-style: italic;
  font-weight: 600;
  font-size: 13px;
  fill: var(--walnut-soft);
  text-anchor: middle;
  letter-spacing: 0.02em;
}

.scene {
  display: flex;
  align-items: flex-end;
  justify-content: center;
  gap: 10px;
  margin: 6px auto 18px;
  max-width: 880px;
  position: relative;
}
.scene .wheel-wrap {
  flex: 0 0 auto;
  width: min(440px, 70vw);
  align-self: center;
  order: 2;
}
.bench-wagon {
  flex: 0 0 auto;
  width: 156px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-end;
  margin-bottom: 76px;
  cursor: pointer;
  transition: transform .25s ease;
  position: relative;
  order: 1;
  background: none;
  border: none;
  padding: 0;
  font: inherit;
  color: inherit;
}
.bench-wagon:hover { transform: translateY(-4px); }
.bench-wagon:focus-visible {
  outline: 2px solid var(--terracotta);
  outline-offset: 4px;
  border-radius: 8px;
}
.runner-wrap {
  flex: 0 0 auto;
  width: 132px;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  margin-bottom: 106px;
  order: 3;
}
.runner {
  position: relative;
  width: 132px;
  height: 140px;
  cursor: pointer;
}
.runner.paused img,
.runner.paused::before {
  animation-play-state: paused !important;
}
.runner img {
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 132px;
  height: auto;
  transform: translateX(-50%);
  image-rendering: pixelated;
  image-rendering: crisp-edges;
  opacity: 0;
}
@keyframes runner-cycle {
  0%,       12.5% { opacity: 1; }
  12.5001%, 100%  { opacity: 0; }
}
.runner img.f0 { animation: runner-cycle 960ms steps(1, end) infinite       0ms; }
.runner img.f1 { animation: runner-cycle 960ms steps(1, end) infinite    -120ms; }
.runner img.f2 { animation: runner-cycle 960ms steps(1, end) infinite    -240ms; }
.runner img.f3 { animation: runner-cycle 960ms steps(1, end) infinite    -360ms; }
.runner img.f4 { animation: runner-cycle 960ms steps(1, end) infinite    -480ms; }
.runner img.f5 { animation: runner-cycle 960ms steps(1, end) infinite    -600ms; }
.runner img.f6 { animation: runner-cycle 960ms steps(1, end) infinite    -720ms; }
.runner img.f7 { animation: runner-cycle 960ms steps(1, end) infinite    -840ms; }
.runner::before {
  content: "";
  position: absolute;
  bottom: 4px;
  left: 50%;
  width: 64px; height: 6px;
  transform: translateX(-50%);
  background: radial-gradient(closest-side, rgba(62,44,32,.22), rgba(62,44,32,0));
  animation: runner-shadow 960ms ease-in-out infinite;
}
@keyframes runner-shadow {
  0%, 100% { transform: translateX(-50%) scaleX(0.85); opacity: .55; }
  50%      { transform: translateX(-50%) scaleX(1.00); opacity: .85; }
}

@media (prefers-reduced-motion: reduce) {
  .runner img, .runner::before { animation: none; }
  .runner img.f0 { opacity: 1; }
  .bench-wagon, .bench-wagon .wagon-cover, .bench-cover,
  .bench-overlay, .bench-card, .bench-clip {
    transition: none;
  }
  .bench-wagon:hover, .bench-wagon:hover .wagon-cover { transform: none; }
}

/* =====================================================
   BOOK WAGON — the bench as a small cart beside the wheel
   ===================================================== */
.wagon-body {
  width: 100%;
  background: linear-gradient(180deg, #D7C3A6, #CBB596);
  border: 2px solid #9A7D5C;
  border-radius: 12px 12px 8px 8px;
  padding: 12px 10px 10px;
  box-shadow: var(--shadow), inset 0 1px 0 rgba(255,255,255,.25);
  position: relative;
}
.wagon-body::before {
  content: '';
  position: absolute;
  left: 6px; right: 6px; top: 4px;
  height: 3px;
  border-radius: 2px;
  background: rgba(255,255,255,0.25);
}

.wagon-covers {
  display: flex;
  align-items: flex-end;
  justify-content: center;
  gap: 5px;
  height: 104px;
  position: relative;
  margin-bottom: 6px;
}
.wagon-cover {
  width: 42px;
  height: 96px;
  border-radius: 4px;
  overflow: hidden;
  box-shadow: 0 6px 14px rgba(75,53,39,0.22), 0 0 0 1px rgba(255,255,255,0.4) inset;
  flex-shrink: 0;
  transition: transform .18s ease;
}
.wagon-cover img { width: 100%; height: 100%; object-fit: cover; filter: sepia(0.14) saturate(0.92); display: block; }
.wagon-cover .cover-placeholder {
  width: 100%; height: 100%;
  background: var(--bg-card-hi);
  border: 1px dashed var(--line);
}
.bench-wagon:hover .wagon-cover { transform: translateY(-3px); }
.wagon-cover.tilt-0 { transform: rotate(-5deg) translateY(6px); }
.wagon-cover.tilt-1 { transform: rotate(0deg) translateY(0); }
.wagon-cover.tilt-2 { transform: rotate(4deg) translateY(5px); }
.bench-wagon:hover .wagon-cover.tilt-0 { transform: rotate(-5deg) translateY(-2px); }
.bench-wagon:hover .wagon-cover.tilt-1 { transform: rotate(0deg) translateY(-6px); }
.bench-wagon:hover .wagon-cover.tilt-2 { transform: rotate(4deg) translateY(-3px); }

.wagon-label {
  text-align: center;
  font-family: var(--font-display);
  font-size: 12px;
  font-weight: 600;
  color: var(--walnut);
  line-height: 1.2;
  display: block;
}
.wagon-sublabel {
  display: block;
  font-size: 10px;
  font-family: var(--font-body);
  color: var(--walnut-soft);
  font-weight: 600;
  letter-spacing: 0.04em;
}

.wagon-wheels {
  display: flex;
  justify-content: space-between;
  width: 108px;
  margin-top: -8px;
  position: relative;
  z-index: 2;
}
.wagon-wheel {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: #6B5039;
  border: 2px solid #4E3A29;
  box-shadow: 0 2px 4px rgba(0,0,0,.15);
  display: block;
}
.wagon-wheel::after {
  content: '';
  display: block;
  width: 5px; height: 5px;
  border-radius: 50%;
  background: #A68B6A;
  margin: 6px auto 0;
}

@media (max-width: 640px) {
  .scene {
    flex-wrap: wrap;
    justify-content: center;
    gap: 8px;
    margin-bottom: 2px;
  }
  .scene .wheel-wrap {
    width: min(360px, 88vw);
    order: 0;
    flex-basis: 100%;
    display: flex;
    justify-content: center;
  }
  .bench-wagon {
    width: 124px;
    margin-bottom: 0;
    margin-top: 4px;
    order: 1;
  }
  .runner-wrap {
    width: 92px;
    margin-bottom: 0;
    margin-top: 4px;
    order: 2;
  }
  .runner { width: 92px; height: 96px; }
  .runner img { width: 92px; }
  .wagon-covers { height: 84px; }
  .wagon-cover { width: 34px; height: 78px; }
  .wagon-wheels { width: 86px; }
  .wagon-wheel { width: 18px; height: 18px; }
  .wagon-wheel::after { margin-top: 4px; }
}

/* =====================================================
   BENCH OVERLAY — expanded shelf + vault
   ===================================================== */
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.bench-overlay {
  position: fixed;
  inset: 0;
  background: rgba(232,220,196,0.88);
  backdrop-filter: blur(3px);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  opacity: 0;
  pointer-events: none;
  transition: opacity .35s ease;
  z-index: 50;
}
.bench-overlay.open {
  opacity: 1;
  pointer-events: auto;
}

.bench-card {
  background: var(--bg-card);
  border: 1.5px solid var(--line);
  border-radius: var(--radius);
  box-shadow: var(--shadow-hover);
  max-width: 720px;
  width: 100%;
  max-height: 90vh;
  overflow-y: auto;
  padding: 28px 30px 32px;
  transform: translateY(16px) scale(0.98);
  transition: transform .35s ease;
  position: relative;
}
.bench-overlay.open .bench-card {
  transform: translateY(0) scale(1);
}

.bench-card-close {
  position: absolute;
  top: 14px;
  right: 18px;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 1.5px solid var(--line);
  background: var(--bg-card-hi);
  color: var(--walnut-soft);
  font-size: 20px;
  line-height: 1;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
}
.bench-card-close:hover,
.bench-card-close:focus-visible {
  color: var(--terracotta);
  border-color: var(--terracotta);
  outline: none;
}

.bench-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 28px;
}

.bench-section-head {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  margin-bottom: 14px;
}
.bench-section-head h4 {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 600;
  margin: 0;
}
.bench-count {
  font-size: 12px;
  color: var(--walnut-soft);
}

.bench-cover-row {
  display: flex;
  align-items: flex-end;
  gap: 12px;
  padding: 6px 4px 14px;
  position: relative;
}
.bench-cover-row::after {
  content: '';
  position: absolute;
  left: 4px; right: 4px; bottom: 4px;
  height: 8px;
  border-radius: 8px;
  background: linear-gradient(180deg, #8a5c40, #5f3d29);
  box-shadow: 0 6px 14px rgba(75,53,39,0.18);
  z-index: 0;
}
.bench-cover {
  position: relative;
  z-index: 1;
  width: 56px;
  height: 84px;
  border-radius: 5px;
  overflow: hidden;
  box-shadow: 0 8px 18px rgba(75,53,39,0.22), 0 0 0 1px rgba(255,255,255,0.5) inset;
  flex-shrink: 0;
  transition: transform .16s ease;
  display: block;
}
.bench-cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  filter: sepia(0.16) saturate(0.92) brightness(0.98) contrast(0.97);
}
.bench-cover-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-card-hi);
  border: 1px dashed var(--line);
  font-size: 10px;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  color: var(--walnut-soft);
}
.bench-cover:hover { transform: translateY(-4px); }
.bench-cover.tilt-l { transform: rotate(-3deg); }
.bench-cover.tilt-r { transform: rotate(3deg); }
.bench-cover.lift { margin-bottom: 6px; }

.bench-shelf-divider {
  height: 1px;
  margin: 8px 0 12px;
  background: repeating-linear-gradient(90deg, rgba(101,65,45,0.18) 0 4px, transparent 4px 8px);
}

.bench-section-foot {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 12px;
  color: var(--walnut-soft);
}
.bench-tag { color: var(--sage-deep); }
.bench-empty {
  color: var(--walnut-soft);
  font-size: 14px;
  margin: 8px 0;
}

.bench-clip-stack {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
